#include "../uwvm_int_translate_strict_common.h"

namespace
{
    using namespace ::uwvm2test::uwvm_int_strict;
#if defined(UWVM_ENABLE_UWVM_INT_HEAVY_COMBINE_OPS) && defined(UWVM_ENABLE_UWVM_INT_EXTRA_HEAVY_COMBINE_OPS)
    [[nodiscard]] constexpr ::std::uint8_t base64_value(unsigned char c) noexcept
    {
        if(c >= static_cast<unsigned char>('A') && c <= static_cast<unsigned char>('Z'))
        {
            return static_cast<::std::uint8_t>(c - static_cast<unsigned char>('A'));
        }
        if(c >= static_cast<unsigned char>('a') && c <= static_cast<unsigned char>('z'))
        {
            return static_cast<::std::uint8_t>((c - static_cast<unsigned char>('a')) + 26);
        }
        if(c >= static_cast<unsigned char>('0') && c <= static_cast<unsigned char>('9'))
        {
            return static_cast<::std::uint8_t>((c - static_cast<unsigned char>('0')) + 52);
        }
        if(c == static_cast<unsigned char>('+')) { return 62u; }
        if(c == static_cast<unsigned char>('/')) { return 63u; }
        return 0xffu;
    }

    [[nodiscard]] byte_vec base64_decode(char const* in, ::std::size_t len) noexcept
    {
        byte_vec out{};
        if(in == nullptr || len == 0uz) { return out; }

        out.reserve((len / 4uz) * 3uz);

        ::std::uint32_t val{};
        int valb{-8};
        for(::std::size_t i{}; i < len; ++i)
        {
            unsigned char const c = static_cast<unsigned char>(in[i]);
            if(c == static_cast<unsigned char>('=')) { break; }

            ::std::uint8_t const d = base64_value(c);
            if(d == 0xffu) { out.clear(); return out; }

            val = (val << 6u) | static_cast<::std::uint32_t>(d);
            valb += 6;

            if(valb >= 0)
            {
                ::std::uint8_t const byte =
                    static_cast<::std::uint8_t>((val >> static_cast<unsigned>(valb)) & 0xffu);
                out.push_back(static_cast<::std::byte>(byte));
                valb -= 8;
            }
        }

        return out;
    }

    [[nodiscard]] byte_vec chacha20_megafuse_reference_wasm() noexcept
    {
        // Keep this test hermetic: embed the reference wasm in C++ (no external data files).
        static constexpr char k_chacha20_wasm_b64[] =
            ""
            ""
            ""
            ""
            ""
            ""
            "";
        return base64_decode(k_chacha20_wasm_b64, sizeof(k_chacha20_wasm_b64) - 1uz);
    }
#endif

    [[nodiscard]] int test_translate_chacha20_megafuse(char const* argv0) noexcept
    {
        // This mega-fuse exists only in extra-heavy builds (hash-guarded).
#if !defined(UWVM_ENABLE_UWVM_INT_HEAVY_COMBINE_OPS) || !defined(UWVM_ENABLE_UWVM_INT_EXTRA_HEAVY_COMBINE_OPS)
        (void)argv0;
        return 0;
#else
        (void)argv0;
        static auto trap_unexpected = []() noexcept { ::fast_io::fast_terminate(); };
        optable::unreachable_func = +trap_unexpected;
        optable::trap_invalid_conversion_to_integer_func = +trap_unexpected;
        optable::trap_integer_divide_by_zero_func = +trap_unexpected;
        optable::trap_integer_overflow_func = +trap_unexpected;
        optable::call_func = +[](::std::size_t, ::std::size_t, ::std::byte**) { ::fast_io::fast_terminate(); };
        optable::call_indirect_func = +[](::std::size_t, ::std::size_t, ::std::size_t, ::std::byte**) { ::fast_io::fast_terminate(); };

        auto wasm = chacha20_megafuse_reference_wasm();
        UWVM2TEST_REQUIRE(wasm.size() == 19541uz);

        auto prep = prepare_runtime_from_wasm(wasm, u8"uwvm2test_chacha20_megafuse");
        UWVM2TEST_REQUIRE(prep.mod != nullptr);
        runtime_module_t const& rt = *prep.mod;

        // Tailcall mode is required by the mega-op ABI.
        constexpr optable::uwvm_interpreter_translate_option_t opt{.is_tail_call = true};

        ::uwvm2::validation::error::code_validation_error_impl err{};
        optable::compile_option cop{};
        auto cm = compiler::compile_all_from_uwvm_single_func<opt>(rt, cop, err);
        UWVM2TEST_REQUIRE(err.err_code == ::uwvm2::validation::error::code_validation_error_code::ok);

        constexpr optable::uwvm_interpreter_stacktop_currpos_t curr{};
        constexpr auto tuple =
            compiler::details::make_interpreter_tuple<opt>(::std::make_index_sequence<compiler::details::interpreter_tuple_size<opt>()>{});

        auto const exp_mega = optable::translate::get_uwvmint_chacha20_block_fixed_key_run_fptr_from_tuple<opt>(curr, tuple);

        ::std::size_t hits{};
        ::std::size_t hit_idx{SIZE_MAX};
        for(::std::size_t i{}; i < cm.local_funcs.size(); ++i)
        {
            auto const& bc = cm.local_funcs.index_unchecked(i).op.operands;
            if(bytecode_contains_fptr(bc, exp_mega))
            {
                ++hits;
                hit_idx = i;
            }
        }

        // The reference module contains exactly one matched ChaCha20 block function.
        UWVM2TEST_REQUIRE(hits == 1uz);
        UWVM2TEST_REQUIRE(hit_idx != SIZE_MAX);

        // Postcondition: the mega-fused body is tiny (single mega-op + immediates + return).
        UWVM2TEST_REQUIRE(cm.local_funcs.index_unchecked(hit_idx).op.operands.size() < 128uz);

        return 0;
#endif
    }
}  // namespace

int main(int argc, char** argv)
{
    try
    {
        (void)argc;
        return test_translate_chacha20_megafuse(argv != nullptr ? argv[0] : nullptr);
    }
    catch(...)
    {
        return ::uwvm2test::uwvm_int_strict::fail(__LINE__, "uncaught exception");
    }
}
